userDefinedCss:
:root {
  /* Dracula Classic */
  --bg: #282a36;
  --fg: #f8f8f2;
  --bg-secondary: #44475a;
  --selection: #6272a4;
  --comment: #6272a4;
  --red: #ff5555;
  --orange: #ffb86c;
  --yellow: #f1fa8c;
  --green: #50fa7b;
  --cyan: #8be9fd;
  --purple: #bd93f9;
  --pink: #ff79c6;
  --shadow: rgba(0, 0, 0, 0.4);
}
@media (prefers-color-scheme: light) {
  :root {
    /* Alucard Classic */
    --bg: #fffbeb;
    --fg: #1f1f1f;
    --bg-secondary: #cfcfde;
    --selection: #cfcfde;
    --comment: #6c664b;
    --red: #cb3a2a;
    --orange: #a34d14;
    --yellow: #846e15;
    --green: #14710a;
    --cyan: #036a96;
    --purple: #644ac9;
    --pink: #a3144d;
    --shadow: rgba(0, 0, 0, 0.15);
  }
}

/* Hint boxes — injected into page shadow root */
.LH {
  background: var(--bg);
  font-size: 12px;
  border: 0.25em solid var(--orange);
  border-radius: 0.34em;
  box-shadow: 0 0.1em 0.6em 0.1em var(--shadow);
}
.LH > span {
  color: var(--fg);
  font-size: inherit;
  text-shadow: none;
}
.LH .MC {
  color: var(--comment);
}
/* HUD */
.HUD:after {
  background: var(--bg) !important;
  border: 1px solid var(--comment) !important;
}
.HUD.D:after {
  background: var(--bg) !important;
}

