body {
  background-color: var(--bg-secondary);
}
#bar {
  background-color: var(--selection);
  border-bottom-color: var(--comment);
}
#input {
  color: var(--fg);
  background-color: var(--bg);
  border-color: var(--comment);
  box-shadow: var(--pink) 0px 0px 1px;
}
#list {
  background-color: var(--bg-secondary);
}
.item {
  border-bottom-color: var(--comment);
  color: var(--fg);
}
.item:hover, .item.s {
  background-color: var(--selection);
}
.item .top {
  color: var(--fg);
}
.item a {
  color: var(--green);
}
match {
  color: var(--orange);
  font-weight: bold;
}
#input::selection {
  background-color: var(--cyan);
  color: var(--bg);
}
